(function () {
  var form = document.getElementById('mcp-server-config');
  if (!form) {
    return;
  }
  function tools(cat) {
    return form.querySelectorAll('.mcp-tool[data-mcp-category="' + cat + '"]');
  }
  function updateCategory(cat) {
    var all = tools(cat);
    var checked = 0;
    all.forEach(function (t) {
      if (t.checked) {
        checked += 1;
      }
    });
    var box = form.querySelector('.mcp-tool-category[data-mcp-category="' + cat + '"]');
    if (box) {
      box.checked = (checked === all.length);
      box.indeterminate = (checked !== 0 && checked !== all.length);
    }
  }
  form.querySelectorAll('.mcp-tool-category').forEach(function (box) {
    box.addEventListener('change', function () {
      var cat = box.getAttribute('data-mcp-category');
      tools(cat).forEach(function (t) {
        if (!t.disabled) {
          t.checked = box.checked;
        }
      });
      updateCategory(cat);
    });
  });
  form.querySelectorAll('.mcp-tool').forEach(function (t) {
    t.addEventListener('change', function () {
      updateCategory(t.getAttribute('data-mcp-category'));
    });
  });
  form.querySelectorAll('.mcp-tool-category').forEach(function (box) {
    updateCategory(box.getAttribute('data-mcp-category'));
  });
})();
